    // Search inventory,


    searchInventory: async function(term) {
        if (handlers._isSearching) return; // Prevent overlapping searches
        handlers._isSearching = true;

        try {
            store.setState({ searchTerm: term });
            if (!term || term.length === 0) {
                // Clear search - reload full inventory
                await handlers.loadInventory();
                if (store.state.currentPage === 'inventory') {
                    const pageContent = pages.inventory();
                    document.querySelector('.page-content').innerHTML = pageContent;
                    // Restore focus to search input after DOM update
                    requestAnimationFrame(() => {
                        const searchInput = document.getElementById('inventory-search');
                        if (searchInput) {
                            searchInput.focus();
                            searchInput.setSelectionRange(searchInput.value.length, searchInput.value.length);
                        }
                    });
                }
                return;
            }
            if (term.length < 2) {
                return;
            }

            const data = await api.get(`/inventory?search=${encodeURIComponent(term)}&limit=200`);
            store.setState({ inventory: data?.items || [] });
            // Re-render inventory page without triggering router
            if (store.state.currentPage === 'inventory') {
                const pageContent = pages.inventory();
                document.querySelector('.page-content').innerHTML = pageContent;
                // Restore focus to search input after DOM update
                requestAnimationFrame(() => {
                    const searchInput = document.getElementById('inventory-search');
                    if (searchInput) {
                        searchInput.value = term;
                        searchInput.focus();
                        searchInput.setSelectionRange(term.length, term.length);
                    }
                });
            }
        } catch (error) {
            console.error('Search failed:', error);
            toast.error('Search failed. Please try again.');
        } finally {
            handlers._isSearching = false;
        }
    },


    debouncedSearch: (() => {
        let searchTimeout = null;
        return function(term) {
            clearTimeout(searchTimeout);
            searchTimeout = setTimeout(() => handlers.searchInventory(term), 300);
        };
    })(),


