    // Duplicate an inventory item,


    duplicateItem: async function(itemId) {
        const item = (store.state.inventory || []).find(i => i.id === itemId);
        if (!item) {
            toast.error('Item not found');
            return;
        }

        try {
            const newItem = { ...item };
            delete newItem.id;
            delete newItem.created_at;
            delete newItem.updated_at;
            newItem.title = `${item.title} (Copy)`;
            newItem.sku = item.sku ? `${item.sku}-COPY` : null;

            const response = await api.post('/inventory', newItem);
            store.setState({ inventory: [...(store.state.inventory || []), response] });
            toast.success('Item duplicated');
            if (response?.id) {
                auditLog.log('create', 'inventory', response.id, { source: 'duplicate', original: itemId });
            }
            router.navigate('inventory');
        } catch (error) {
            toast.error('Failed to duplicate item');
        }
    },

    // Create listing from inventory item,


    createListingFromItem: function(itemId) {
        const item = store.state.inventory.find(i => i.id === itemId);
        if (!item) {
            toast.error('Item not found');
            return;
        }
        store.setState({ prefillListingItem: item });
        router.navigate('listings');
        setTimeout(() => modals.addListing?.(), 100);
    },

    // Bulk tag items,


    bulkTag: async function(ids) {
        const tag = await modals.prompt('Enter tag to add to all selected items:', { title: 'Add Tag', placeholder: 'e.g. vintage' });
        if (!tag) return;

        try {
            for (const id of ids) {
                const item = store.state.inventory.find(i => i.id === id);
                if (item) {
                    const tags = JSON.parse(item.tags || '[]');
                    if (!tags.includes(tag)) {
                        tags.push(tag);
                        await api.put(`/inventory/${id}`, { tags: JSON.stringify(tags) });
                        item.tags = JSON.stringify(tags);
                    }
                }
            }
            toast.success(`Tagged ${ids.length} items with "${tag}"`);
            router.navigate('inventory');
        } catch (error) {
            toast.error('Failed to tag items');
        }
    },

