    bulkUpdatePrice: async function() {
        const ids = store.state.selectedItems;
        if (ids.length === 0) return toast.warning('No items selected');

        const input = await modals.prompt(`Adjust price for ${ids.length} item(s). Enter a percentage (e.g. +10%, -15%) or dollar amount (e.g. +5.00, -2.50):`, { title: 'Bulk Price Adjustment', placeholder: '+10% or -$2.50' });
        if (!input) return;

        let type, value;
        if (input.includes('%')) {
            type = 'percentage';
            value = parseFloat(input.replace('%', '').replace('+', ''));
            if (isNaN(value)) return toast.error('Invalid percentage');
        } else {
            type = 'amount';
            value = parseFloat(input.replace('+', ''));
            if (isNaN(value)) return toast.error('Invalid amount');
        }

        try {
            await api.ensureCSRFToken();
            await api.post('/inventory/bulk', {
                action: 'updatePrice',
                ids,
                data: { adjustment: { type, value } }
            });

            const message = type === 'percentage'
                ? `${ids.length} item(s) price adjusted by ${value > 0 ? '+' : ''}${value}%`
                : `${ids.length} item(s) price adjusted by $${value > 0 ? '+' : ''}${value.toFixed(2)}`;
            toast.success(message);

            store.setState({ selectedItems: [] });
            await handlers.loadInventory();

            // Hide the bulk menu
            const menu = document.getElementById('selection-menu');
            menu?.classList.add('hidden');
        } catch (error) {
            toast.error(error.message);
        }
    },

