    updateProfitCalc: function() {
        const purchaseCost = parseFloat(document.getElementById('profit-purchase-cost')?.value) || 0;
        const sellingPrice = parseFloat(document.getElementById('profit-selling-price')?.value) || 0;
        const feeSelect = document.getElementById('profit-platform-fee');
        const shippingCost = parseFloat(document.getElementById('profit-shipping-cost')?.value) || 0;
        const otherCosts = parseFloat(document.getElementById('profit-other-costs')?.value) || 0;

        let platformFeePercent = parseFloat(feeSelect?.value) || 0;
        if (feeSelect?.value === 'custom') {
            platformFeePercent = parseFloat(document.getElementById('profit-custom-fee')?.value) || 0;
        }

        // Calculate
        const platformFee = (sellingPrice * platformFeePercent) / 100;
        const totalCosts = purchaseCost + platformFee + shippingCost + otherCosts;
        const netProfit = sellingPrice - totalCosts;
        const profitMargin = sellingPrice > 0 ? (netProfit / sellingPrice) * 100 : 0;
        const roi = purchaseCost > 0 ? (netProfit / purchaseCost) * 100 : 0;

        // Update result cards
        const netProfitEl = document.getElementById('result-net-profit');
        if (netProfitEl) {
            netProfitEl.textContent = (netProfit >= 0 ? '$' : '-$') + Math.abs(netProfit).toFixed(2);
            netProfitEl.className = 'profit-result-value ' + (netProfit >= 0 ? 'positive' : 'negative');
        }

        const marginEl = document.getElementById('result-margin');
        if (marginEl) {
            marginEl.textContent = profitMargin.toFixed(1) + '%';
            marginEl.className = 'profit-result-value ' + (profitMargin >= 0 ? 'positive' : 'negative');
        }

        const roiEl = document.getElementById('result-roi');
        if (roiEl) {
            roiEl.textContent = (roi >= 0 ? '' : '-') + Math.abs(roi).toFixed(1) + '%';
            roiEl.className = 'profit-result-value ' + (roi >= 0 ? 'positive' : 'negative');
        }

        const feeEl = document.getElementById('result-platform-fee');
        if (feeEl) feeEl.textContent = '$' + platformFee.toFixed(2);

        // Update breakdown
        const breakdownEls = {
            'breakdown-selling': '$' + sellingPrice.toFixed(2),
            'breakdown-platform': '-$' + platformFee.toFixed(2),
            'breakdown-purchase': '-$' + purchaseCost.toFixed(2),
            'breakdown-shipping': '-$' + shippingCost.toFixed(2),
            'breakdown-other': '-$' + otherCosts.toFixed(2)
        };
        for (const [id, text] of Object.entries(breakdownEls)) {
            const el = document.getElementById(id);
            if (el) el.textContent = text;
        }

        const totalEl = document.getElementById('breakdown-total');
        if (totalEl) {
            totalEl.textContent = (netProfit >= 0 ? '$' : '-$') + Math.abs(netProfit).toFixed(2);
            totalEl.className = netProfit >= 0 ? 'positive' : 'negative';
        }

        // Update profit indicator bar
        const profitBar = document.getElementById('profit-bar');
        const profitIndicator = document.getElementById('profit-indicator');
        if (profitBar && profitIndicator) {
            // Scale: -100% to +100% ROI maps to 0% to 100% width
            const barWidth = Math.min(100, Math.max(0, 50 + (roi / 2)));
            profitBar.style.width = barWidth + '%';
            profitIndicator.className = 'profit-indicator ' + (netProfit >= 0 ? 'profit' : 'loss');
        }
    },

