    toggleListingColumn: function(columnId, isVisible) {
        const visibleColumns = store.state.listingsVisibleColumns ||
            ['image', 'item', 'platform', 'price', 'status', 'stale', 'listed'];

        if (isVisible && !visibleColumns.includes(columnId)) {
            visibleColumns.push(columnId);
        } else if (!isVisible) {
            const index = visibleColumns.indexOf(columnId);
            if (index > -1) visibleColumns.splice(index, 1);
        }

        store.setState({ listingsVisibleColumns: [...visibleColumns] });

        // Re-render table
        if (store.state.currentPage === 'listings') {
            const pageContent = pages.listings();
            document.querySelector('.page-content').innerHTML = pageContent;
        }
    },

