    toggleBulkPriceMethod: function(method) {
        document.getElementById('bulk-percentage-section').style.display = method === 'percentage' ? 'block' : 'none';
        document.getElementById('bulk-fixed-section').style.display = method === 'fixed' ? 'block' : 'none';
        document.getElementById('bulk-roundup-section').style.display = method === 'roundup' ? 'block' : 'none';
    },


    previewBulkPriceUpdate: function() {
        const inventory = store.state.inventory || [];
        const selectedIds = store.state.selectedInventoryIds || [];
        const items = selectedIds.length > 0
            ? inventory.filter(i => selectedIds.includes(i.id))
            : inventory;

        const method = document.querySelector('input[name="bulk-method"]:checked')?.value;
        const previewItems = items.slice(0, 5).map(item => {
            const oldPrice = parseFloat(item.list_price) || 0;
            let newPrice = oldPrice;

            if (method === 'percentage') {
                const pct = parseFloat(document.getElementById('bulk-pct').value) || 0;
                newPrice = oldPrice * (1 + pct / 100);
            } else if (method === 'fixed') {
                const fixed = parseFloat(document.getElementById('bulk-fixed').value) || 0;
                newPrice = oldPrice + fixed;
            } else if (method === 'roundup') {
                const round = parseFloat(document.getElementById('bulk-round').value) || 1;
                if (round < 1) {
                    newPrice = Math.floor(oldPrice) + round;
                } else {
                    newPrice = Math.ceil(oldPrice / round) * round;
                }
            }

            newPrice = Math.max(0, newPrice);
            return { title: item.title || item.name, oldPrice, newPrice };
        });

        const previewEl = document.getElementById('bulk-price-preview-list');
        if (previewEl) {
            previewEl.innerHTML = previewItems.map(p => `
                <div class="preview-row">
                    <span class="preview-title">${escapeHtml(p.title)}</span>
                    <span class="preview-old">$${p.oldPrice.toFixed(2)}</span>
                    <span class="preview-arrow">→</span>
                    <span class="preview-new ${p.newPrice < p.oldPrice ? 'decrease' : p.newPrice > p.oldPrice ? 'increase' : ''}">$${p.newPrice.toFixed(2)}</span>
                </div>
            `).join('') + (items.length > 5 ? `<div class="preview-more">...and ${items.length - 5} more items</div>` : '');
        }
    },


    applyBulkPriceUpdate: function() {
        const inventory = store.state.inventory || [];
        const selectedIds = store.state.selectedInventoryIds || [];
        const method = document.querySelector('input[name="bulk-method"]:checked')?.value;

        let updatedCount = 0;
        inventory.forEach(item => {
            if (selectedIds.length > 0 && !selectedIds.includes(item.id)) return;

            const oldPrice = parseFloat(item.list_price) || 0;
            let newPrice = oldPrice;

            if (method === 'percentage') {
                const pct = parseFloat(document.getElementById('bulk-pct').value) || 0;
                newPrice = oldPrice * (1 + pct / 100);
            } else if (method === 'fixed') {
                const fixed = parseFloat(document.getElementById('bulk-fixed').value) || 0;
                newPrice = oldPrice + fixed;
            } else if (method === 'roundup') {
                const round = parseFloat(document.getElementById('bulk-round').value) || 1;
                if (round < 1) {
                    newPrice = Math.floor(oldPrice) + round;
                } else {
                    newPrice = Math.ceil(oldPrice / round) * round;
                }
            }

            item.list_price = Math.max(0, newPrice);
            updatedCount++;
        });

        store.setState({ inventory });
        toast.success(`Updated prices for ${updatedCount} items`);
        modals.close();
    },

