    // Return Rate Analytics,


    restoreItem: async function(itemId) {
        if (!await modals.confirm('Restore this item? It will be moved back to your inventory as a draft.', { title: 'Restore Item', confirmText: 'Restore' })) return;

        try {
            await api.ensureCSRFToken();
            await api.post(`/inventory/${itemId}/restore`);
            toast.success('Item restored successfully');

            // Reload deleted items
            await this.loadDeletedItems();

            // Re-render the page
            if (store.state.currentPage === 'recently-deleted') {
                const pageContent = pages.recentlyDeleted();
                document.querySelector('.page-content').innerHTML = pageContent;
            }
        } catch (error) {
            toast.error(error.message || 'Failed to restore item');
        }
    },


    permanentlyDeleteItem: async function(itemId) {
        if (!await modals.confirm('PERMANENTLY DELETE this item?<br><br>This action CANNOT be undone. The item will be removed forever.', { title: 'Permanent Delete', confirmText: 'Delete Forever', danger: true })) return;

        try {
            await api.ensureCSRFToken();
            await api.delete(`/inventory/${itemId}/permanent`);
            toast.success('Item permanently deleted');

            // Reload deleted items
            await this.loadDeletedItems();

            // Re-render the page
            if (store.state.currentPage === 'recently-deleted') {
                const pageContent = pages.recentlyDeleted();
                document.querySelector('.page-content').innerHTML = pageContent;
            }
        } catch (error) {
            toast.error(error.message || 'Failed to delete item');
        }
    },


    toggleAutomation: async function(ruleId, enabled) {
        try {
            await api.post(`/automations/${ruleId}/toggle`);

            // Update state locally instead of reloading to avoid re-rendering
            const updatedAutomations = store.state.automations.map(rule =>
                rule.id === ruleId ? { ...rule, is_enabled: enabled ? 1 : 0 } : rule
            );
            store.setState({ automations: updatedAutomations });

            // Manually update the badge in the DOM without full re-render
            const badges = document.querySelectorAll('.badge');
            badges.forEach(badge => {
                const parentDiv = badge.closest('.flex.items-center.justify-between');
                if (parentDiv && parentDiv.querySelector(`input[onchange*="${ruleId}"]`)) {
                    badge.textContent = enabled ? 'Active' : 'Paused';
                    badge.className = `badge ${enabled ? 'badge-success' : 'badge-gray'}`;
                }
            });

            toast.success(`Automation ${enabled ? 'enabled' : 'disabled'}`);
        } catch (error) {
            toast.error(error.message);
        }
    },


