    toggleAutomationPreset: async function(presetId, presetName, enabled, exists) {
        try {
            if (!exists && enabled) {
                await api.ensureCSRFToken();
                await api.post('/automations/from-preset', { presetId });
                toast.success(`${presetName} enabled!`);
            } else if (exists) {
                await api.post(`/automations/${presetId}/toggle`);
                toast.success(`${presetName} ${enabled ? 'enabled' : 'paused'}!`);
            }

            // Visual feedback animation on the card
            const cards = document.querySelectorAll('.automation-card');
            cards.forEach(card => {
                const toggle = card.querySelector(`input[onchange*="${presetId}"]`);
                if (toggle) {
                    card.classList.add(enabled ? 'automation-enabled-flash' : 'automation-disabled-flash');
                    setTimeout(() => {
                        card.classList.remove('automation-enabled-flash', 'automation-disabled-flash');
                    }, 600);
                }
            });

            await handlers.loadAutomations();
            if (store.state.currentPage === 'automations') {
                const pageContent = pages.automations();
                document.querySelector('.page-content').innerHTML = pageContent;
            }
        } catch (error) {
            toast.error(error.message);
            if (store.state.currentPage === 'automations') {
                const pageContent = pages.automations();
                document.querySelector('.page-content').innerHTML = pageContent;
            }
        }
    },


    bulkTogglePlatform: async function(platform, enable) {
        try {
            const allPresets = store.state.automations || [];
            const presets = allPresets.filter(a => a.platform === platform || (a.platform === 'all' && platform !== 'all'));
            let count = 0;
            await api.ensureCSRFToken();
            for (const preset of presets) {
                const isEnabled = !!preset.is_enabled;
                if (enable && !isEnabled) {
                    await api.post(`/automations/${preset.id}/toggle`);
                    count++;
                } else if (!enable && isEnabled) {
                    await api.post(`/automations/${preset.id}/toggle`);
                    count++;
                }
            }
            toast.success(`${count} ${platform} automation${count !== 1 ? 's' : ''} ${enable ? 'enabled' : 'disabled'}`);
            await handlers.loadAutomations();
            if (store.state.currentPage === 'automations') {
                const pageContent = pages.automations();
                document.querySelector('.page-content').innerHTML = pageContent;
            }
        } catch (error) {
            toast.error(error.message);
        }
    },

