    updateAutomationSchedule: function(setting, value) {
        const current = store.state.automationSchedule || {
            frequency: 'daily',
            startTime: '09:00',
            endTime: '21:00',
            daysOfWeek: [1, 2, 3, 4, 5, 6, 0],
            timezone: Intl.DateTimeFormat().resolvedOptions().timeZone
        };

        if (setting === 'toggleDay') {
            const dayIndex = parseInt(value);
            if (current.daysOfWeek.includes(dayIndex)) {
                current.daysOfWeek = current.daysOfWeek.filter(d => d !== dayIndex);
            } else {
                current.daysOfWeek.push(dayIndex);
                current.daysOfWeek.sort((a, b) => a - b);
            }
        } else {
            current[setting] = value;
        }

        store.setState({ automationSchedule: current });

        // Save to localStorage
        try {
            localStorage.setItem('vaultlister_automation_schedule', JSON.stringify(current));
        } catch (e) {
            console.error('Failed to save automation schedule:', e);
        }

        // Re-render the page
        if (store.state.currentPage === 'automations') {
            const pageContent = pages.automations();
            document.querySelector('.page-content').innerHTML = pageContent;
        }
    },

