    // Relist a listing,


    relistListing: async function(listingId) {
        try {
            await api.ensureCSRFToken();
            const data = await api.post(`/listings/${listingId}/relist`, { reason: 'manual' });

            if (data.listing) {
                // Update the listing in state
                const listings = store.state.listings.map(l =>
                    l.id === listingId ? { ...l, ...data.listing } : l
                );
                store.setState({ listings });

                toast.success(data.message || 'Listing relisted successfully');

                // Re-render current page
                if (store.state.currentPage && pages[store.state.currentPage]) {
                    renderApp(pages[store.state.currentPage]());
                }
            }
        } catch (error) {
            console.error('Failed to relist listing:', error);
            toast.error('Failed to relist listing: ' + error.message);
        }
    },

