    previewListingImages: function(input, platform) {
        const container = document.getElementById(`${platform}-selected-images`);
        const progressContainer = document.getElementById(`${platform}-image-progress`);
        const progressBar = document.getElementById(`${platform}-progress-bar`);
        const progressText = document.getElementById(`${platform}-progress-text`);
        if (!container || !input.files) return;

        container.innerHTML = '';
        let files = Array.from(input.files);
        if (files.length === 0) { if (progressContainer) progressContainer.style.display = 'none'; return; }

        const oversized = files.filter(f => f.size > 10 * 1024 * 1024);
        if (oversized.length > 0) {
            toast.error(`${oversized.length} image(s) exceed 10MB limit and were removed.`);
            files = files.filter(f => f.size <= 10 * 1024 * 1024);
            if (files.length === 0) { if (progressContainer) progressContainer.style.display = 'none'; return; }
        }

        if (progressContainer) progressContainer.style.display = 'block';
        let loaded = 0;

        files.forEach((file, idx) => {
            const reader = new FileReader();
            reader.onload = (e) => {
                const img = document.createElement('div');
                img.style.cssText = 'width:64px;height:64px;border-radius:6px;overflow:hidden;position:relative;border:2px solid var(--gray-200);';
                img.innerHTML = `<img src="${e.target.result}" style="width:100%;height:100%;object-fit:cover;">
                    <span style="position:absolute;bottom:0;left:0;right:0;background:rgba(0,0,0,0.6);color:white;font-size:10px;text-align:center;padding:1px;">${idx + 1}</span>`;
                container.appendChild(img);

                loaded++;
                const pct = Math.round(loaded / files.length * 100);
                if (progressBar) progressBar.style.width = pct + '%';
                if (progressText) progressText.textContent = loaded === files.length ? `${files.length} image(s) ready` : `Processing ${loaded}/${files.length}...`;
            };
            reader.readAsDataURL(file);
        });
    },


    toggleCrosslistMode: function(mode) {
        const unifiedSection = document.getElementById('unified-mode-section');
        const customizedSection = document.getElementById('customized-mode-section');

        if (mode === 'unified') {
            unifiedSection?.classList.remove('hidden');
            customizedSection?.classList.add('hidden');
        } else {
            unifiedSection?.classList.add('hidden');
            customizedSection?.classList.remove('hidden');
            // Update platform panels based on selected platforms
            this.updatePlatformPanels();
        }
    },


    updatePlatformPanels: function() {
        const platformCheckboxes = document.querySelectorAll('.platform-checkbox');
        const selectedPlatforms = Array.from(platformCheckboxes)
            .filter(cb => cb.checked)
            .map(cb => cb.value);

        const panels = document.querySelectorAll('.platform-customization-panel');
        panels.forEach(panel => {
            const platform = panel.getAttribute('data-platform');
            if (selectedPlatforms.includes(platform)) {
                panel.classList.remove('hidden');
            } else {
                panel.classList.add('hidden');
            }
        });
    },


    applyPriceAdjustment: function(platform, adjustPercent, basePrice) {
        const priceInput = document.querySelector(`input[name="${platform}Price"]`);
        if (!priceInput) return;

        const adjustment = parseFloat(adjustPercent) / 100;
        const newPrice = basePrice * (1 + adjustment);
        priceInput.value = newPrice.toFixed(2);
    },

