    applyAIResults: function() {
        if (!this._aiGeneratedData) {
            return toast.error('No AI results to apply');
        }

        // Get values from AI results before closing the modal
        const title = document.getElementById('ai-result-title')?.value;
        const description = document.getElementById('ai-result-description')?.value;
        const brand = document.getElementById('ai-result-brand')?.value;
        const category = document.getElementById('ai-result-category')?.value;
        const color = document.getElementById('ai-result-color')?.value;
        const condition = document.getElementById('ai-result-condition')?.value;
        const size = document.getElementById('ai-result-size')?.value;
        const tags = document.getElementById('ai-result-tags')?.value;
        const price = document.getElementById('ai-result-price')?.value;

        // Store the data for after modal opens
        const formData = { title, description, brand, category, color, condition, size, tags, price };

        // Close wizard modal
        modals.close();

        // Wait for modal to close, then open Add Item modal and populate with retry
        setTimeout(() => {
            // Open the Add Item modal
            modals.addItem();

            // Retry finding the form up to 5 times with increasing delays
            let attempts = 0;
            const maxAttempts = 5;
            const tryPopulate = () => {
                attempts++;
                const form = document.getElementById('add-item-form');
                if (form) {
                    this._populateAddItemForm(formData);
                    toast.success('AI results applied to form!');
                } else if (attempts < maxAttempts) {
                    setTimeout(tryPopulate, 100 * attempts);
                } else {
                    toast.error('Could not apply AI results. Please try again or enter details manually.');
                }
            };
            setTimeout(tryPopulate, 150);
        }, 100);
    },


