    batchUpdateSkus: async function(ruleId, onlyEmpty = true) {
        if (!ruleId) {
            toast.error('Please select a rule');
            return;
        }

        const rules = store.state.skuRules || [];
        const rule = rules.find(r => r.id === ruleId);

        if (!await modals.confirm(`Apply rule "${rule?.name || 'Unknown'}" to ${onlyEmpty ? 'items without SKUs' : 'ALL items'}? This cannot be undone.`, { title: 'Apply SKU Rule', confirmText: 'Apply', danger: true })) {
            return;
        }

        try {
            store.setState({ skuBatchProgress: { status: 'running', updated: 0 } });
            await api.ensureCSRFToken();
            const result = await api.post('/sku-rules/batch-update', {
                ruleId,
                onlyEmpty
            });

            store.setState({ skuBatchProgress: { status: 'complete', updated: result.updated } });
            toast.success(`Updated ${result.updated} item(s)`);
            modals.close();

            // Reload inventory to show updated SKUs
            await handlers.loadInventory();
        } catch (error) {
            store.setState({ skuBatchProgress: null });
            toast.error('Batch update failed: ' + error.message);
        }
    },

    // Insert pattern token at cursor position in pattern input,


    insertPatternToken: function(token) {
        const input = document.querySelector('input[name="pattern"]');
        if (!input) return;

        const start = input.selectionStart;
        const end = input.selectionEnd;
        const value = input.value;

        input.value = value.substring(0, start) + token + value.substring(end);
        input.focus();
        input.setSelectionRange(start + token.length, start + token.length);

        // Trigger live preview
        handlers.livePreviewSkuPattern(input.value);
    },

